bash_commands.command:
# Update imports from django.test - replace RequestFactory with TestRequestBuilder
find tests -name "*.py" -type f -exec sed -i 's/from django\.test import \(.*\)RequestFactory\(.*\)$/from django.test import \1TestRequestBuilder\2/g' {} \;

# Also handle from django.test.client imports
find tests -name "*.py" -type f -exec sed -i 's/from django\.test\.client import \(.*\)RequestFactory\(.*\)$/from django.test.client import \1TestRequestBuilder\2/g' {} \;

# Replace RequestFactory instantiations with TestRequestBuilder
find tests -name "*.py" -type f -exec sed -i 's/RequestFactory()/TestRequestBuilder()/g' {} \;

echo "Replacements completed"

